import{_ as r,c as n,o as a,ah as t}from"./chunks/framework.C-x9UAyH.js";const s="/aks_func_ppal_orquestador.png",o="/az_estructura_k8s.png",b=JSON.parse('{"title":"Introducción a Azure Pipelines y Orquestación de Contenedores","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"azure/aks.md","filePath":"azure/aks.md","lastUpdated":1760649277000}'),i={name:"azure/aks.md"};function l(d,e,c,u,g,p){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="introduccion-a-azure-pipelines-y-orquestacion-de-contenedores" tabindex="-1">Introducción a Azure Pipelines y Orquestación de Contenedores <a class="header-anchor" href="#introduccion-a-azure-pipelines-y-orquestacion-de-contenedores" aria-label="Permalink to &quot;Introducción a Azure Pipelines y Orquestación de Contenedores&quot;">​</a></h1><h2 id="🎯-¿que-es-la-orquestacion-de-contenedores" tabindex="-1">🎯 ¿Qué es la Orquestación de Contenedores? <a class="header-anchor" href="#🎯-¿que-es-la-orquestacion-de-contenedores" aria-label="Permalink to &quot;🎯 ¿Qué es la Orquestación de Contenedores?&quot;">​</a></h2><p>La <strong>orquestación de contenedores</strong> automatiza la gestión de aplicaciones contenedorizadas en entornos escalables, como arquitecturas de <strong>microservicios</strong>. Un orquestador simplifica tareas esenciales para garantizar despliegues <strong>eficientes</strong> y <strong>confiables</strong> en clústeres.</p><p align="center"><img src="'+s+'" width="800" alt="azure aks"></p><h2 id="🛠️-herramientas-de-orquestacion" tabindex="-1">🛠️ Herramientas de Orquestación <a class="header-anchor" href="#🛠️-herramientas-de-orquestacion" aria-label="Permalink to &quot;🛠️ Herramientas de Orquestación&quot;">​</a></h2><ul><li><strong>Kubernetes (K8s)</strong> 🌟: Plataforma de código abierto líder para gestionar contenedores a gran escala, ideal para cargas de trabajo complejas.</li><li><strong>Docker Swarm</strong> 🐳: Solución integrada de Docker, perfecta para entornos más simples.</li><li><strong>Apache Mesos</strong> 🖥️: Abstrae recursos del centro de datos, pero requiere complementos adicionales.</li></ul><h2 id="🚀-kubernetes" tabindex="-1">🚀 Kubernetes <a class="header-anchor" href="#🚀-kubernetes" aria-label="Permalink to &quot;🚀 Kubernetes&quot;">​</a></h2><p><strong>Kubernetes</strong> es la herramienta más popular para orquestar contenedores, ofreciendo <strong>portabilidad</strong>, <strong>escalabilidad</strong> y <strong>extensibilidad</strong>. Se integra perfectamente con servicios como <strong>Azure Kubernetes Service (AKS)</strong>, combinado con <strong>Azure Container Registry (ACR)</strong> para despliegues seguros y eficientes.</p><h3 id="✨-ventajas-de-kubernetes" tabindex="-1">✨ Ventajas de Kubernetes <a class="header-anchor" href="#✨-ventajas-de-kubernetes" aria-label="Permalink to &quot;✨ Ventajas de Kubernetes&quot;">​</a></h3><ul><li>🌍 <strong>Portabilidad</strong>: Usa archivos <strong>YAML</strong> para despliegues sin rediseñar la infraestructura.</li><li>📈 <strong>Escalabilidad</strong>: Gestiona el ciclo de vida de contenedores según necesidades.</li><li>🔧 <strong>Extensibilidad</strong>: Su <strong>API</strong> permite integraciones con herramientas <strong>CI/CD</strong> y lenguajes variados.</li></ul><hr><h2 id="🏗️-arquitectura-de-kubernetes" tabindex="-1">🏗️ Arquitectura de Kubernetes <a class="header-anchor" href="#🏗️-arquitectura-de-kubernetes" aria-label="Permalink to &quot;🏗️ Arquitectura de Kubernetes&quot;">​</a></h2><p>Un clúster de <strong>Kubernetes</strong> está compuesto por:</p><ul><li><strong>Nodos de trabajo</strong> 🖥️: Ejecutan aplicaciones contenedorizadas. Incluyen: <ul><li><strong>Kubelet</strong>: Agente que gestiona contenedores.</li><li><strong>Kube-proxy</strong>: Maneja el tráfico de red.</li><li><strong>Entorno de ejecución de contenedores</strong>: Ejecuta los contenedores.</li></ul></li><li><strong>Plano de control</strong> 🎮: Gestiona la orquestación mediante: <ul><li><strong>kube-api-server</strong>: Expone la API de Kubernetes.</li><li><strong>kube-scheduler</strong>: Asigna cargas de trabajo a nodos.</li><li><strong>Controller</strong>: Mantiene el estado deseado.</li></ul></li></ul><hr><h2 id="📖-glosario-de-kubernetes" tabindex="-1">📖 Glosario de Kubernetes <a class="header-anchor" href="#📖-glosario-de-kubernetes" aria-label="Permalink to &quot;📖 Glosario de Kubernetes&quot;">​</a></h2><ul><li><strong>Pod</strong> 🧳: Unidad básica que agrupa contenedores relacionados.</li><li><strong>Service</strong> 🌐: Define cómo acceder a un conjunto de pods (microservicio).</li><li><strong>Controlador</strong> ⚙️: Mantiene el estado deseado (ej. <strong>ReplicaSet</strong>, <strong>Deployment</strong>).</li><li><strong>kubectl</strong> 🖱️: Herramienta CLI para gestionar clústeres.</li><li><strong>Kubelet</strong> 🤖: Agente que ejecuta contenedores en nodos.</li><li><strong>Kube-proxy</strong> 🔌: Gestiona la red virtual y el tráfico.</li><li><strong>kube-api-server</strong> 📡: Expone la API de Kubernetes.</li><li><strong>kube-scheduler</strong> 📅: Asigna cargas de trabajo a nodos.</li></ul><hr><h2 id="☁️-azure-kubernetes-service-aks" tabindex="-1">☁️ Azure Kubernetes Service (AKS) <a class="header-anchor" href="#☁️-azure-kubernetes-service-aks" aria-label="Permalink to &quot;☁️ Azure Kubernetes Service (AKS)&quot;">​</a></h2><p><strong>AKS</strong> simplifica la gestión de clústeres <strong>Kubernetes</strong> en Azure, integrándose con <strong>Microsoft Entra ID</strong> y <strong>Azure Container Registry (ACR)</strong>. Facilita el despliegue de aplicaciones portátiles en contenedores con la potencia de la infraestructura de Azure. 🚀</p><hr><h2 id="estructura-de-kubernetes" tabindex="-1">Estructura de Kubernetes <a class="header-anchor" href="#estructura-de-kubernetes" aria-label="Permalink to &quot;Estructura de Kubernetes&quot;">​</a></h2><p align="center"><img src="'+o+'" width="800" alt="estructura k8s"></p><h2 id="💾-gestion-de-almacenamiento-y-redes-en-kubernetes" tabindex="-1">💾 Gestión de Almacenamiento y Redes en Kubernetes <a class="header-anchor" href="#💾-gestion-de-almacenamiento-y-redes-en-kubernetes" aria-label="Permalink to &quot;💾 Gestión de Almacenamiento y Redes en Kubernetes&quot;">​</a></h2><h3 id="💿-almacenamiento" tabindex="-1">💿 Almacenamiento <a class="header-anchor" href="#💿-almacenamiento" aria-label="Permalink to &quot;💿 Almacenamiento&quot;">​</a></h3><ul><li><strong>Volúmenes</strong> 📂: Kubernetes utiliza volúmenes para gestionar almacenamiento.</li><li><strong>Volúmenes Persistentes</strong> 💾: Proveen almacenamiento duradero, accesible tras reinicios (ej. <strong>azureDisk</strong> para discos de Azure).</li><li><strong>Volúmenes Efímeros</strong> 🗑️: Almacenamiento temporal que se pierde al reiniciar un contenedor.</li></ul><h3 id="🌐-redes" tabindex="-1">🌐 Redes <a class="header-anchor" href="#🌐-redes" aria-label="Permalink to &quot;🌐 Redes&quot;">​</a></h3><ul><li><strong>Redes de Contenedores</strong> 🔗: Contenedores en un pod comparten la <strong>IP</strong> y configuración de red, como si estuvieran en el mismo host.</li><li><strong>Redes de Clústeres</strong> 🕸️: Facilitan comunicación entre pods en un clúster.</li><li><strong>Servicios Externos</strong> 🌍: Permiten acceso a aplicaciones desde fuera del clúster.</li><li><strong>Servicios Internos</strong> 🔒: Gestionan comunicación entre recursos dentro del clúster.</li><li><strong>CNI (Interfaz de Red de Contenedor)</strong> 🔌: Habilita comunicación directa entre pods y aplica políticas de red.</li></ul><h3 id="🔧-configuraciones-clave" tabindex="-1">🔧 Configuraciones Clave <a class="header-anchor" href="#🔧-configuraciones-clave" aria-label="Permalink to &quot;🔧 Configuraciones Clave&quot;">​</a></h3><ul><li><strong>Contenedores</strong>: Comparten la red del pod. 🛢️</li><li><strong>Pods</strong>: Cada pod tiene una <strong>IP única</strong>. 📍</li><li><strong>Servicios</strong>: Cada servicio tiene una <strong>IP virtual</strong>. 🌐</li><li><strong>Clústeres</strong>: Cada nodo tiene su propia <strong>IP</strong>. 💻</li><li><strong>Comunicación del Clúster</strong>: Usa <strong>kube-dns</strong> y <strong>kube-proxy</strong> para enrutar tráfico de servicios a pods. 🚦</li></ul>',30)])])}const h=r(i,[["render",l]]);export{b as __pageData,h as default};
